// app/invoices/page.js

import moment from 'moment-jalaali'; 
// CRITICAL FIX: The path goes up two directories to reach the root-level 'lib' folder
import { prisma } from '../../lib/prisma'; 

// --- Data Structure defined using JSDoc (JavaScript compatible) ---
/**
 * @typedef {object} Invoice
 * @property {number} id
 * @property {string | null} date - Shamsi date string for display
 * @property {string} title
 * @property {string} amount - Converted to string for display
 * @property {string | null} store_name
 * @property {string} type
 * @property {string} category
 * @property {string | null} description
 * @property {boolean} has_receipt
 * @property {boolean} has_invoice
 * @property {Date} createdAt
 */

// Function to fetch all invoices using the Prisma client
async function getInvoices() {
  try {
    // 1. Fetch data using Prisma (You would add WHERE clauses here for true server-side filtering)
    const rows = await prisma.invoice.findMany({
      orderBy: [
        { date: 'desc' },
        { id: 'desc' },
      ],
    });
    
    // 2. Process the rows (map to convert the date and amount for display)
    /** @type {Invoice[]} */
    const invoices = rows.map(row => ({
      ...row,
      // Convert the database Date object to Shamsi format (Persian Calendar)
      date: row.date ? moment(row.date).format('jYYYY/jMM/jDD') : null,
      // Convert Decimal amount to a string for display
      amount: row.amount.toString(), 
    }));

    return invoices; 
  } catch (err) {
    // Log the detailed error (visible in your terminal/Vercel logs)
    console.error('Prisma Fetch Error (Invoices Page):', err); 
    
    // Throw a generic error to the client
    throw new Error('Failed to load invoices. Please check the server logs for the detailed database error.'); 
  }
}

// Main Server Component to render the page
export default async function InvoicesPage() {
  const invoices = await getInvoices();
  
  // --- Start of Component Rendering (JSX) ---
  
  return (
    <div style={styles.container}>
      <h2 style={styles.heading}>لیست فاکتورها</h2>

      {/* 🚨 FILTERING STRUCTURE ADDED HERE 🚨 */}
      <div style={styles.filterContainer}>
        <input 
          type="text" 
          placeholder="جستجو بر اساس نام فروشگاه یا عنوان..." 
          style={styles.filterInput}
          // Note: Full filtering requires this component to be converted to a 
          // 'use client' component or complex URL state management.
        />
        <a href="/add-invoice" style={styles.buttonLink}>
          افزودن فاکتور جدید
        </a>
      </div>
      
      {invoices.length === 0 ? (
        <p style={styles.noData}>هیچ فاکتوری یافت نشد.</p>
      ) : (
        <table style={styles.table}>
          <thead style={styles.thead}>
            <tr>
              {/* 🚨 DATE COLUMN ADDED BACK TO THE HEADER 🚨 */}
              <th style={styles.th}>تاریخ</th> 
              <th style={styles.th}>نام فروشگاه</th>
              <th style={styles.th}>عنوان</th>
              <th style={styles.th}>مبلغ (ریال)</th>
              <th style={styles.th}>نوع</th>
              <th style={styles.th}>دسته</th>
              <th style={styles.th}>رسید</th>
              <th style={styles.th}>فاکتور</th>
            </tr>
          </thead>
          <tbody>
            {invoices.map((invoice) => (
              <tr key={invoice.id} style={styles.tr}>
                {/* 🚨 DATE COLUMN ADDED BACK TO THE BODY 🚨 */}
                <td style={styles.td}>{invoice.date}</td> 
                <td style={styles.td}>{invoice.store_name || 'N/A'}</td>
                <td style={styles.td}>{invoice.title}</td>
                <td style={styles.td}>{invoice.amount}</td>
                <td style={styles.td}>{invoice.type}</td>
                <td style={styles.td}>{invoice.category}</td>
                {/* Displaying boolean fields with icons */}
                <td style={styles.td}>{invoice.has_receipt ? '✅' : '❌'}</td>
                <td style={styles.td}>{invoice.has_invoice ? '✅' : '❌'}</td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
      
    </div>
  );
}

